import { b64toBlob } from "./blob";

export const URLManager = new (class _URLManager {
  static contentMap = new Map();

  getContentUrl(content, base64 = false) {
    if (window.URL && "createObjectURL" in URL && !this.checkValidUrl(content)) {
      if (!_URLManager.contentMap.has(content)) {
        const blob = base64
          ? b64toBlob(
              content.split(",")[1],
              content
                .split(",")[0]
                .split(":")[1]
                .split(";")[0]
            )
          : new Blob([content], {
              type: "text/html"
            });

        _URLManager.contentMap.set(content, URL.createObjectURL(blob));
      }

      return _URLManager.contentMap.get(content);
    }

    return content;
  }

  revokeContentUrls(excludeUrls) {
    if (window.URL && "createObjectURL" in URL) {
      _URLManager.contentMap.forEach((_, url) => {
        if (!excludeUrls || !excludeUrls.has(url)) {
          URL.revokeObjectURL(url);
          _URLManager.contentMap.delete(url);
        }
      });
    }
  }

  checkValidUrl(url) {
    return new RegExp(
      "^(https?:\\/\\/)?" + // protocol
      "((([a-z\\d]([a-z\\d-]*[a-z\\d])*)\\.?)+[a-z]{2,}|" + // domain name
      "((\\d{1,3}\\.){3}\\d{1,3}))" + // OR ip (v4) address
      "(\\:\\d+)?(\\/[-a-z\\d%_.~+]*)*" + // port and path
      "(\\?[;&a-z\\d%_.~+=-]*)?" + // query string
        "(\\#[-a-z\\d_]*)?$", // fragment locator
      "i"
    ).test(url);
  }
})();
