import styles from "./EventsField.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import EventsContainer from "../EventsContainer/EventsContainer";
import EventsPoint from "../EventPoint/EventPoint";
import TimelineField from "../TimelineField/TimelineField";
import ReactTooltip from "react-tooltip";
import { Modals } from "../../../../../constants/modals";
import { isMobile } from "../../../../../../common/constants/user-agent";

export default class EventsField extends PureComponent {
  static defaultTopOffset = 25;
  static pointStep = 50;
  static pointShortStep = 30;
  static elementAdditionalIndent = 10;

  static propTypes = {
    start: PropTypes.instanceOf(Date),
    containerCount: PropTypes.number.isRequired,
    events: PropTypes.array.isRequired,
    interval: PropTypes.number.isRequired,
    intervalType: PropTypes.string.isRequired,
    showModal: PropTypes.func.isRequired
  };

  state = {
    minHeight: 0,
    sortedEvents: [],
    topOffset: []
  };
  minHeight = null;
  points = [];
  tooltips = [];

  getSortedEventsFromPoints = (points, sortedEvents) => {
    const pointKeys = Object.keys(points);
    pointKeys.forEach(el => {
      const element = points[el].getContainerBoundingClientRect();
      if (sortedEvents[element.eventIndex]) {
        sortedEvents[element.eventIndex].xEnd = element.bounding.x;
        const length = points[el].getTimelineLength() + EventsPoint.height;

        if (length > sortedEvents[element.eventIndex].width) {
          sortedEvents[element.eventIndex].width = length;
        }
      } else {
        sortedEvents[element.eventIndex] = {
          eventIndex: element.eventIndex,
          xStart: element.bounding.x,
          top: EventsField.defaultTopOffset,
          width: element.bounding.width,
          height: element.bounding.height,
          prompt: element.prompt,
          labelWidth: element.bounding.labelWidth,
          labelHeight: element.bounding.labelHeight
        };
      }
    });
  };

  touchStartHandler = () => {
    const shownTooltips = this.tooltips.filter(el => el.refs.tooltip.state.show);

    if (shownTooltips.length > 0) {
      shownTooltips.map(el => ReactTooltip.hide(el.refs.root));
    }
  };

  componentWillUnmount() {
    if (isMobile) {
      document.removeEventListener("touchstart", this.touchStartHandler);
    }
  }

  componentDidMount() {
    const { points } = this;

    if (isMobile) {
      this.tooltips = Object.keys(points)
        .map(el => points[el].getTooltipRef())
        .filter(el => el);

      document.addEventListener("touchstart", this.touchStartHandler);
    }

    const sortedEvents = [];
    this.getSortedEventsFromPoints(points, sortedEvents);

    let minHeight = 0;
    sortedEvents.map(element => {
      const collisionArray = sortedEvents.filter(
        collisionElement =>
          collisionElement.eventIndex <= element.eventIndex &&
          collisionElement !== element &&
          (collisionElement.xStart + collisionElement.width + EventsField.elementAdditionalIndent >=
            element.xStart ||
            collisionElement.xStart +
              collisionElement.labelWidth +
              EventsField.elementAdditionalIndent >=
              element.xStart)
      );
      let currentTop = element.xEnd
        ? 2 * EventsField.defaultTopOffset
        : EventsField.defaultTopOffset;
      const compareTops = (currentTop, height, xStart) => el =>
        (currentTop + height >= el.top && currentTop + height <= el.top + el.height) ||
        (el.top + el.height >= currentTop && el.top + el.height <= currentTop + height) ||
        (el.labelHeight > 0 &&
          el.labelWidth + el.xStart >= xStart &&
          ((currentTop + height >= el.top - EventsField.defaultTopOffset &&
            currentTop + height <= el.top - EventsField.defaultTopOffset + el.labelHeight) ||
            (el.top - EventsField.defaultTopOffset + el.labelHeight >= currentTop &&
              el.top - EventsField.defaultTopOffset + el.labelHeight <= currentTop + height)));
      const reducer = (element1, element2) => {
        return element1.top > element2.top ? element1 : element2;
      };
      for (let i = 0; i < collisionArray.length; i++) {
        const currentCollisions = collisionArray.filter(
          compareTops(
            currentTop - (element.xEnd ? EventsField.defaultTopOffset : 0),
            element.height,
            element.xStart
          )
        );
        if (currentCollisions.length > 0) {
          const collisionElement = currentCollisions.reduce(reducer);

          currentTop =
            collisionElement.top +
            (collisionElement.height - (collisionElement.xEnd ? EventsField.defaultTopOffset : 0)) +
            EventsField.elementAdditionalIndent +
            (element.xEnd ? EventsField.defaultTopOffset : 0);
        } else {
          break;
        }
      }
      element.top = currentTop;

      if (element.top > minHeight) {
        minHeight = element.top;
      }
      return element;
    });

    this.setState({
      sortedEvents: sortedEvents,
      minHeight: minHeight
    });
  }

  get styleContainer() {
    return { minHeight: this.state.minHeight + EventsField.pointStep };
  }

  get eventsPoints() {
    const arr = [];
    const sortedEvents = [];
    const { startBC, start, containerCount, events, interval, intervalType } = this.props;

    for (let i = 0; i < events.length; i++) {
      this.insertPoint(sortedEvents, events[i], start, startBC, interval, intervalType, i);
    }

    let startDate = TimelineField.getProperDateObject(start);
    let currentStartBC = startBC;
    let eventIndex = 0;
    for (let j = 0; j < containerCount; j++) {
      const borderKey =
        j === 0
          ? EventsContainer.borderLeftKey
          : j === containerCount - 1
          ? EventsContainer.borderRightKey
          : null;

      arr.push(
        <EventsContainer key={"EventsContainer" + j} borderKey={borderKey}>
          {sortedEvents[j] &&
            this.pointsInsideInterval(sortedEvents[j], j, startDate, currentStartBC, eventIndex)}
        </EventsContainer>
      );

      eventIndex += sortedEvents[j] ? sortedEvents[j].length : 0;

      const nextStart = TimelineField.getNextDate(
        startDate,
        intervalType,
        interval,
        currentStartBC
      );
      startDate = nextStart.date;
      currentStartBC = nextStart.BC;
    }

    return arr;
  }

  onEventDescriptionClick = (index, e) => {
    const { events, showModal } = this.props;
    const startDateLocale = events[index].startDate + (events[index].isStartDateBC ? " BC" : "");
    let endDateLocale = "";
    if (events[index].endDate) {
      endDateLocale = events[index].endDate + (events[index].isEndDateBC ? " BC" : "");
    }

    const rangeString = !events[index].endDate
      ? startDateLocale
      : events[index].endDate
      ? TimelineField.firstDateGreaterSecond(
          TimelineField.getProperDateObject(events[index].startDate),
          TimelineField.getProperDateObject(events[index].endDate),
          events[index].isStartDateBC,
          events[index].isEndDateBC
        )
        ? `${endDateLocale} - ${startDateLocale}`
        : `${startDateLocale} - ${endDateLocale}`
      : null;

    showModal(
      {
        type: Modals.DANGER_HTML_CONTENT,
        title: events[index].prompt,
        additionalInfo: <em>{rangeString}</em>,
        content: events[index].description,
        buttonText: "OK",
        scrolling: true,
        modalAutofocus: true
      },
      e
    );
  };

  pointsInsideInterval(eventsToDisplay, containerIndex, startDate, currentStartBC, eventIndex) {
    const { intervalType, interval } = this.props;
    const { sortedEvents } = this.state;
    const endDateObject = TimelineField.getNextDate(
      startDate,
      intervalType,
      interval,
      currentStartBC
    );
    const endDate = endDateObject.date;
    const endDateBC = endDateObject.BC;
    let rangeDiffer = TimelineField.dateDifferWorkaround(
      startDate,
      endDate,
      currentStartBC,
      endDateBC
    );

    const msInPx = EventsContainer.clientWidth / rangeDiffer;

    return eventsToDisplay.map((element, index) => {
      let timelineLength = null;
      if (!element.startRef) {
      } else {
        if (containerIndex === element.startRef.containerIndex) {
          timelineLength = -element.startRef.left;
        } else {
          timelineLength =
            (containerIndex - element.startRef.containerIndex - 1) * EventsContainer.fullWidth +
            (EventsContainer.fullWidth - element.startRef.left);
        }
      }

      let dateDiffer = null;
      const dateToCount = TimelineField.getProperDateObject(element.date);
      dateDiffer = TimelineField.dateDifferWorkaround(
        startDate,
        dateToCount,
        currentStartBC,
        element.dateBC
      );

      let left = Math.floor(dateDiffer * msInPx);

      element.left = left;
      element.containerIndex = containerIndex;

      const startDateLocale = element.date + (element.dateBC ? " BC" : "");
      let endDateLocale = "";
      if (element.endDate) {
        endDateLocale = element.endDate + (element.endDateBC ? " BC" : "");
      }

      const date = !element.endDate
        ? startDateLocale
        : element.endDate
        ? TimelineField.firstDateGreaterSecond(
            TimelineField.getProperDateObject(element.date),
            TimelineField.getProperDateObject(element.endDate),
            element.dateBC,
            element.endDateBC
          )
          ? `${endDateLocale} - ${startDateLocale}`
          : `${startDateLocale} - ${endDateLocale}`
        : null;

      const showLabel = element.single || !!element.endDate;

      return (
        <EventsPoint
          ref={ref => (this.points["eventsPoint" + (eventIndex + index)] = ref)}
          top={sortedEvents[element.eventIndex] ? sortedEvents[element.eventIndex].top : 0}
          prompt={element.prompt}
          left={left}
          key={"eventsPoint" + element.top + index}
          timelineLength={showLabel ? undefined : timelineLength}
          date={date}
          eventIndex={element.eventIndex}
          onClick={this.onEventDescriptionClick}
          showDescription={element.showDescription}
          showLabel={showLabel}
          single={element.single}
        />
      );
    });
  }

  insertPoint(array, event, start, startBC, interval, intervalType, index) {
    let currentStart = start;
    let currentStartBC = startBC;
    let dateDiff = TimelineField.getDateDifference(
      currentStart,
      event.startDate,
      intervalType,
      currentStartBC,
      event.isStartDateBC
    );
    let neededContainerStart = Math.floor(dateDiff / interval);

    if (!array[neededContainerStart]) {
      array[neededContainerStart] = [];
    }

    let neededContainerEnd;
    if (event.endDate) {
      dateDiff = TimelineField.getDateDifference(
        currentStart,
        event.endDate,
        intervalType,
        currentStartBC,
        event.isEndDateBC
      );

      neededContainerEnd = Math.floor(dateDiff / interval);
    } else {
      neededContainerEnd = neededContainerStart;
    }

    const commonData = {
      prompt: event.prompt,
      showDescription: !!event.description,
      eventIndex: index
    };
    const startIndex = array[neededContainerStart].push({
      ...commonData,
      date: event.startDate,
      single: !event.endDate,
      endDate: event.endDate,
      endDateBC: event.isEndDateBC,
      endDateContainer: neededContainerEnd,
      dateBC: event.isStartDateBC
    });

    if (event.endDate) {
      if (!array[neededContainerEnd]) {
        array[neededContainerEnd] = [];
      }

      const startPoint = array[neededContainerStart][startIndex - 1];

      array[neededContainerEnd].push({
        ...commonData,
        date: event.endDate,
        startRef: startPoint,
        single: false,
        dateBC: event.isEndDateBC
      });
    }
  }

  render() {
    return (
      <div role="application" style={this.styleContainer} className={styles.eventsContainer}>
        {this.eventsPoints}
      </div>
    );
  }
}
