import styles from "./EventLabel.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import classNames from "classnames";
import Tooltip from "../../../../../../common/components/Tooltip/Tooltip";
import { TOOLTIP_CONTAINER_ID } from "../../../../../../common/constants/tooltip";
import { Key } from "../../../../../../common/constants/keyboard";
import ReactTooltip from "react-tooltip";
import { Classes } from "../../../../../../common/constants/classes";

export default class EventLabel extends PureComponent {
  static promptIndent = 32;
  static propTypes = {
    eventId: PropTypes.number.isRequired,
    buttonId: PropTypes.string.isRequired,
    prompt: PropTypes.string.isRequired,
    drawAbove: PropTypes.bool,
    showDescription: PropTypes.bool.isRequired,
    date: PropTypes.string,
    onClick: PropTypes.func.isRequired
  };

  state = {
    tooltipShown: false
  };

  get styleContainer() {
    return this.props.drawAbove
      ? {
          marginTop: -26,
          marginLeft: -20
        }
      : {};
  }

  keyUpHandler = e => {
    if (e.which === Key.SPACEBAR) {
      const { prompt, date } = this.props;
      const { tooltipShown } = this.state;

      e.preventDefault();
      let currAriaText = "";
      if (tooltipShown) {
        ReactTooltip.hide(this.tooltipRef.refs.root);
      } else {
        ReactTooltip.show(this.tooltipRef.refs.root);
        currAriaText = `${prompt}${date ? `, ${date}` : ""}`;
      }
      this.setState({
        tooltipShown: !tooltipShown,
        ariaText: currAriaText
      });
    }
  };

  blurHandler = () => {
    const { tooltipShown } = this.state;
    if (tooltipShown) {
      ReactTooltip.hide(this.tooltipRef.refs.root);
      this.setState({
        tooltipShown: false,
        ariaText: ""
      });
    }
  };

  getLabelWidth = () => {
    return this.wrapperRef.getBoundingClientRect().width;
  };

  getLabelHeight = () => {
    return this.wrapperRef.getBoundingClientRect().height;
  };

  getTooltipRef = () => {
    return this.tooltipRef;
  };

  render() {
    const { eventId, prompt, buttonId, onClick, showDescription, date } = this.props;
    const { ariaText } = this.state;
    const promptStyle = { marginRight: showDescription ? `${EventLabel.promptIndent}px` : "" };

    return (
      <div
        ref={ref => (this.wrapperRef = ref)}
        className={styles.eventLabelWrapper}
        style={this.styleContainer}
      >
        <Tooltip
          id={`eventLabel${eventId}`}
          text={`${prompt}${date ? `, ${date}` : ""}`}
          portal={document.getElementById(TOOLTIP_CONTAINER_ID)}
          ref={element => (this.tooltipRef = element)}
        >
          <div className={Classes.VISUALLY_HIDDEN} aria-live="polite" aria-atomic="true">
            {ariaText}
          </div>
          <p
            role="button"
            tabIndex="0"
            style={promptStyle}
            onKeyUp={this.keyUpHandler}
            onBlur={this.blurHandler}
          >
            {prompt}
          </p>
        </Tooltip>
        {showDescription && (
          <Button
            id={buttonId}
            className={classNames(
              buttonStyles[buttonId.split("_").join("-")],
              styles.showDescButton
            )}
            onClick={onClick}
          />
        )}
      </div>
    );
  }
}
