import styles from "./EventPoint.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import EventLabel from "../EventLabel/EventLabel";
import { Buttons } from "../../../../../constants/buttons";

export default class EventPoint extends PureComponent {
  static height = 20;
  static defaultPointMargin = 10;

  static propTypes = {
    timelineLength: PropTypes.number,
    top: PropTypes.number.isRequired,
    left: PropTypes.number.isRequired,
    eventIndex: PropTypes.number.isRequired,
    prompt: PropTypes.string.isRequired,
    date: PropTypes.string,
    showDescription: PropTypes.bool.isRequired,
    showLabel: PropTypes.bool,
    single: PropTypes.bool,
    onClick: PropTypes.func.isRequired
  };

  getContainerBoundingClientRect = () => {
    const { prompt, eventIndex, showLabel, single } = this.props;
    let containerBounding = this.containerRef.getBoundingClientRect();

    return {
      prompt: prompt,
      eventIndex: eventIndex,
      bounding: {
        x: containerBounding.x ? containerBounding.x : containerBounding.left,
        width: showLabel
          ? containerBounding.width + this.labelRef.getLabelWidth() + EventPoint.defaultPointMargin
          : containerBounding.width,
        labelWidth: single ? 0 : this.labelRef ? this.labelRef.getLabelWidth() : 0,
        labelHeight: single ? 0 : this.labelRef ? this.labelRef.getLabelHeight() : 0,
        height:
          containerBounding.height + (!single && this.labelRef ? this.labelRef.getLabelHeight() : 0)
      }
    };
  };

  getTimelineLength = () => {
    const { timelineLength } = this.props;

    return timelineLength ? timelineLength : 0;
  };

  get objectWidth() {
    return this.props.timelineLength + this.props.left;
  }

  get styleContainer() {
    return { left: this.props.left, top: this.props.top };
  }

  get styleObject() {
    const width = `${this.objectWidth}px`;

    return {
      height: EventPoint.height,
      marginLeft: `-${width}`,
      width
    };
  }

  onDescriptionButtonClick = e => {
    this.props.onClick.call(null, this.props.eventIndex, e);
  };

  getTooltipRef = () => {
    return this.labelRef ? this.labelRef.getTooltipRef() : false;
  };

  render() {
    const polygonWidth = this.objectWidth;

    return (
      <div
        ref={ref => (this.containerRef = ref)}
        style={this.styleContainer}
        className={styles.eventPointWrapper}
      >
        <div className={styles.eventDot}>
          {!isNaN(this.props.timelineLength) && (
            <svg style={this.styleObject}>
              <polygon
                points={`0,0 ${polygonWidth},0 ${polygonWidth},${EventPoint.height} 0,${
                  EventPoint.height
                }`}
              />
            </svg>
          )}
        </div>
        {this.props.showLabel && (
          <EventLabel
            ref={ref => (this.labelRef = ref)}
            drawAbove={!this.props.single}
            eventId={this.props.eventIndex}
            showDescription={this.props.showDescription}
            buttonId={Buttons.SHOW_EVENT_DESCRIPTION}
            onClick={this.onDescriptionButtonClick}
            prompt={this.props.prompt}
            date={this.props.date}
          />
        )}
      </div>
    );
  }
}
