import styles from "./EventsContainer.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";

export default class EventsContainer extends PureComponent {
  static width = parseInt(styles.tickEventWidth);
  static borderWidth = parseInt(styles.tickEventBorderWidth);
  static fullWidth = EventsContainer.width + EventsContainer.borderWidth * 2;
  static clientWidth = EventsContainer.fullWidth - 20;

  static borderLeftKey = "borderLeftWidth";
  static borderRightKey = "borderRightWidth";
  static propTypes = {
    borderKey: PropTypes.string
  };

  get styleContainer() {
    const { borderKey } = this.props;
    return borderKey ? { [borderKey]: EventsContainer.borderWidth * 2 } : null;
  }

  render() {
    return (
      <div style={this.styleContainer} className={styles.tickEventContainer}>
        {this.props.children}
      </div>
    );
  }
}
