/* eslint react/forbid-foreign-prop-types:off */
import React from "react";
import { connect } from "react-redux";
import buildActions from "../../store/actions";
import CommonPlayer from "../../../common/components/Player/Player";
import Activity from "../_activity/Activity/Activity";

@connect(
  state => ({
    displayMode: state.displayMode,
    displaySetting: state.displaySetting,
    displayIconImage: state.displayIconImage,
    activityName: state.name,
    activityType: state.type
  }),
  buildActions
)
class Player extends CommonPlayer {
  static propTypes = CommonPlayer.propTypes;

  getActivityModal = () => {
    return this.activityModal;
  };

  get activity() {
    return <Activity activityModal={this.getActivityModal} activityAlign={this.activityAlign} />;
  }
}

export default Player;
