import styles from "./TimelineField.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import TimelineTick from "../TimelineTick/TimelineTick";
import { DateList } from "../../../../../../common/constants/date-list";
import EventsField from "../EventsField/EventsField";
import { Timeline } from "../../../../../../common/constants/activities/timeline";

export { styles as timelineFieldStyles };

export default class TimelineField extends PureComponent {
  static propTypes = {
    start: PropTypes.instanceOf(Date),
    events: PropTypes.array.isRequired,
    interval: PropTypes.any.isRequired,
    intervalType: PropTypes.string.isRequired,
    tickCount: PropTypes.number.isRequired,
    showModal: PropTypes.func.isRequired
  };

  static monthCount = 12;

  static getLocaleDateStringWorkaround(date, intervalType) {
    switch (intervalType) {
      case Timeline.INTERVAL_TYPES.year:
        return date.getFullYear();
      case Timeline.INTERVAL_TYPES.month:
        return `${DateList.MONTHS[date.getMonth()]} ${date.getFullYear()}`;
      case Timeline.INTERVAL_TYPES.day:
        const currDate = new Date();
        currDate.setFullYear(2000);
        currDate.setMonth(date.getMonth());
        currDate.setDate(date.getDate());
        const localeDateString = currDate.toDateString();
        return localeDateString.replace("2000", date.getFullYear());
      default:
        return "";
    }
  }

  static getAbsoluteYearDateObject(...args) {
    const year = args[0];
    const month = args[1];
    const day = args[2];
    const date = new Date();
    if (year) {
      date.setFullYear(year);
    }
    if (!isNaN(month)) {
      date.setMonth(month);
    }
    if (day) {
      date.setDate(day);
    }
    date.setHours(0);
    date.setMinutes(0);
    date.setSeconds(0);
    date.setMilliseconds(0);

    return date;
  }

  static dateDifferWorkaround(date1, date2, date1BC, date2BC) {
    if (!!date1BC === !!date2BC && date1BC) {
      const date1Year = date1.getFullYear();
      const finishDate1 = TimelineField.getAbsoluteYearDateObject(date1Year, 11, 31);

      const date2Year = date2.getFullYear();
      const startDate1 = TimelineField.getAbsoluteYearDateObject(date2Year, 0, 1);

      const date1NextYearFinish = TimelineField.getAbsoluteYearDateObject(date1Year - 1, 11, 31);
      const date2PrevYearStart = TimelineField.getAbsoluteYearDateObject(date2Year + 1, 0, 1);

      if (date1Year === date2Year) {
        return date2 - date1;
      }
      return (
        finishDate1 - date1 + (date1NextYearFinish - date2PrevYearStart) + (date2 - startDate1)
      );
    } else if (!!date1BC === !!date2BC && !date1BC) {
      return date2 - date1;
    } else {
      const endDateBC = TimelineField.getAbsoluteYearDateObject(1, 11, 31);

      const startDateAD = TimelineField.getAbsoluteYearDateObject(1, 0, 1);

      return (
        TimelineField.dateDifferWorkaround(date1, endDateBC, true, true) +
        TimelineField.dateDifferWorkaround(startDateAD, date2, false, false)
      );
    }
  }

  static firstDateGreaterSecond(date1, date2, date1BC, date2BC) {
    if (date1BC !== date2BC) {
      return !date1BC;
    } else {
      return (date1 > date2 && !date1BC) || (date2 > date1 && date1BC);
    }
  }

  static isYearLeap(year) {
    return (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;
  }

  static getYearDayCount(year) {
    return TimelineField.isYearLeap(year) ? 366 : 365;
  }

  static getMonthDayCount(month, year) {
    const month31dayArray = [0, 2, 4, 6, 7, 9, 11];

    if (month31dayArray.indexOf(month) >= 0) {
      return 31;
    } else if (month === 1) {
      return TimelineField.isYearLeap(year) ? 29 : 28;
    } else {
      return 30;
    }
  }

  static getProperDateObject(date = null) {
    switch (true) {
      case typeof date === "string":
        const splitedDate = Object.assign([1, 1, 1], date.split(" ").reverse());
        let monthIndex = DateList.MONTHS.indexOf(splitedDate[1]);
        if (monthIndex < 0) {
          monthIndex = 0;
        }
        splitedDate.splice(1, 1, monthIndex);
        const convertedDate = new Date(...splitedDate);
        convertedDate.setFullYear(splitedDate[0]);
        convertedDate.setHours(0, 0, 0, 0);
        return convertedDate;
      case date instanceof Date:
        let currDate = new Date();
        currDate.setDate(1);
        const year = date.getFullYear();
        const month = date.getMonth();
        const day = date.getDate();
        currDate.setFullYear(year);
        currDate.setMonth(month);
        currDate.setDate(day);
        currDate.setHours(0, 0, 0, 0);
        return currDate;
      default:
        date.setHours(0, 0, 0, 0);
        return date;
    }
  }

  static getDateDifference(date1, date2, intervalType, isStartDateBC, isEndDateBC) {
    let startDate = TimelineField.getProperDateObject(date1);
    let endDate = TimelineField.getProperDateObject(date2);
    const sign = isEndDateBC || (!isEndDateBC && !isStartDateBC) ? -1 : 1;

    switch (intervalType) {
      case Timeline.INTERVAL_TYPES.year:
        return Math.abs(
          endDate.getFullYear() +
            sign * startDate.getFullYear() -
            (isStartDateBC && !isEndDateBC ? 1 : 0)
        );
      case Timeline.INTERVAL_TYPES.month:
        if (isEndDateBC === isStartDateBC) {
          const startDateYear = startDate.getFullYear();
          const endDateYear = endDate.getFullYear();
          const yearDiffer = Math.abs(startDateYear - endDateYear);

          if (startDate.getFullYear() === endDate.getFullYear()) {
            return endDate.getMonth() - startDate.getMonth();
          } else {
            return (
              (yearDiffer - 1) * TimelineField.monthCount +
              endDate.getMonth() +
              (TimelineField.monthCount - startDate.getMonth())
            );
          }
        } else {
          return (
            (endDate.getFullYear() - 1) * TimelineField.monthCount +
            endDate.getMonth() +
            ((startDate.getFullYear() - 1) * TimelineField.monthCount +
              (TimelineField.monthCount - startDate.getMonth()))
          );
        }
      case Timeline.INTERVAL_TYPES.day:
        let days = 0;
        if (isEndDateBC === isStartDateBC) {
          if (startDate.getFullYear() !== endDate.getFullYear()) {
            let initYear =
              (startDate.getFullYear() > endDate.getFullYear()
                ? startDate.getFullYear()
                : endDate.getFullYear()) - 1;
            const endYear =
              startDate.getFullYear() > endDate.getFullYear()
                ? endDate.getFullYear()
                : startDate.getFullYear();
            while (initYear > endYear) {
              days += TimelineField.getYearDayCount(initYear);
              initYear--;
            }

            for (let i = startDate.getMonth() + 1; i < TimelineField.monthCount; i++) {
              days += TimelineField.getMonthDayCount(i, startDate.getFullYear());
            }
            for (let i = 0; i < endDate.getMonth(); i++) {
              days += TimelineField.getMonthDayCount(i, endDate.getFullYear());
            }

            days += TimelineField.getMonthDayCount(startDate.getMonth()) - startDate.getDate();
            days += endDate.getDate();
          } else {
            if (startDate.getMonth() !== endDate.getMonth()) {
              let initMonth =
                (startDate.getMonth() > endDate.getMonth()
                  ? startDate.getMonth()
                  : endDate.getMonth()) - 1;
              const endMonth =
                startDate.getMonth() > endDate.getMonth()
                  ? endDate.getMonth()
                  : startDate.getMonth();
              while (initMonth > endMonth) {
                days += TimelineField.getMonthDayCount(initMonth, startDate.getFullYear());
                initMonth--;
              }

              days += TimelineField.getMonthDayCount(startDate.getMonth()) - startDate.getDate();
              days += endDate.getDate();
            } else {
              return startDate.getDate() > endDate.getDate()
                ? startDate.getDate() - endDate.getDate()
                : endDate.getDate() - startDate.getDate();
            }
          }
        } else {
          const firstYear = TimelineField.getProperDateObject("1 Jan 1");
          if (isStartDateBC) {
            days += TimelineField.getDateDifference(firstYear, startDate, intervalType, true, true);
            days += TimelineField.getDateDifference(endDate, firstYear, intervalType, false, false);
          } else {
            days += TimelineField.getDateDifference(firstYear, endDate, intervalType, true, true);
            days += TimelineField.getDateDifference(startDate, firstYear, intervalType, true, true);
          }
        }
        return days;
      default:
    }
  }

  static getNextDate(startDate, intervalType, interval, dateBC) {
    let sign = dateBC ? -1 : 1;
    const firstYear = new Date();
    firstYear.setFullYear(1, 0, 1);
    firstYear.setHours(0, 0, 0, 0);
    const differ = TimelineField.getDateDifference(
      startDate,
      firstYear,
      intervalType,
      dateBC,
      false
    );

    const numericInterval = parseInt(interval);

    let nextDate = TimelineField.getProperDateObject(startDate);

    if (interval > differ && dateBC) {
      sign = 1;
      switch (intervalType) {
        case Timeline.INTERVAL_TYPES.day:
          nextDate.setDate(interval - differ);
          break;
        case Timeline.INTERVAL_TYPES.month:
          nextDate.setMonth(interval - differ);
          break;
        case Timeline.INTERVAL_TYPES.year:
          nextDate.setFullYear(interval - differ + 1);
          break;
        default:
      }
    } else {
      switch (intervalType) {
        case Timeline.INTERVAL_TYPES.day:
          nextDate.setDate(nextDate.getDate() + sign * numericInterval);
          break;
        case Timeline.INTERVAL_TYPES.month:
          let currentMonth = nextDate.getMonth() + numericInterval;
          if (dateBC) {
            if (currentMonth > TimelineField.monthCount - 1) {
              let newYear = nextDate.getFullYear() - currentMonth / TimelineField.monthCount;
              currentMonth = currentMonth % TimelineField.monthCount;
              if (newYear <= 0) {
                newYear = Math.abs(newYear) + 1;
              }
              nextDate.setFullYear(newYear);
            }
          }
          nextDate.setMonth(currentMonth);
          break;
        case Timeline.INTERVAL_TYPES.year:
          nextDate.setFullYear(nextDate.getFullYear() + sign * numericInterval);
          break;
        default:
      }
    }

    let newBC = sign === -1;
    if (nextDate.getFullYear() === 0) {
      nextDate.setFullYear(1);
      newBC = false;
    }

    return {
      date: nextDate,
      BC: newBC
    };
  }

  get ticks() {
    const { intervalType, tickCount, start, startBC } = this.props;
    const interval = parseInt(this.props.interval);
    let dateIterator = TimelineField.getProperDateObject(start),
      dateIteratorBC = startBC,
      dateString;

    return Array(tickCount + 1)
      .fill()
      .map((_, i) => {
        const BCstring = dateIteratorBC && dateIterator.getFullYear() > 0 ? " BC" : "";
        switch (intervalType) {
          case Timeline.INTERVAL_TYPES.day:
            dateString = `${dateIterator.getDate()} ${
              DateList.MONTHS[dateIterator.getMonth()]
            } ${dateIterator.getFullYear()} ${BCstring}`;
            break;
          case Timeline.INTERVAL_TYPES.month:
            dateString = `${
              DateList.MONTHS[dateIterator.getMonth()]
            } ${dateIterator.getFullYear()} ${BCstring}`;
            break;
          case Timeline.INTERVAL_TYPES.year:
            dateString = `${dateIterator.getFullYear()} ${BCstring}`;
            break;
          default:
            dateString = "";
        }
        const nextDate = TimelineField.getNextDate(
          dateIterator,
          intervalType,
          interval,
          dateIteratorBC
        );
        dateIterator = nextDate.date;
        dateIteratorBC = nextDate.BC;

        return <TimelineTick key={"timelineTick" + i} date={dateString} />;
      });
  }

  render() {
    return (
      <div className={styles.container}>
        <div className={styles.axis}>{this.ticks}</div>
        <EventsField
          showModal={this.props.showModal}
          events={this.props.events}
          start={this.props.start}
          startBC={this.props.startBC}
          intervalType={this.props.intervalType}
          interval={parseInt(this.props.interval)}
          containerCount={this.props.tickCount}
        />
      </div>
    );
  }
}
