import React from "react";
import ReactDOM from "react-dom";
import { Provider } from "react-redux";
import reducers from "./store/reducers";
import Player from "./components/Player/Player";
import { StoreFactory } from "../../../common/utils/store";
import { LocaleContext } from "../../utils/context";
import defaultState from "./store/default-state";

export const bootstrap = (node, externalState, locale) => {
  const store = StoreFactory.createStore(defaultState(externalState), reducers);

  ReactDOM.render(
    <Provider store={store}>
      <LocaleContext.Provider value={locale.timeline}>
        <Player />
      </LocaleContext.Provider>
    </Provider>,
    node
  );
};
