import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { connect } from "react-redux";
import { InjectLocale } from "../../../../../decorators/locale";
import buildActions from "../../../store/actions";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import TimelineField, { timelineFieldStyles } from "../TimelineField/TimelineField";
import Modal from "../../../../common/components/Modal/Modal";
import { URLManager } from "../../../../../../common/utils/url";
import { Timeline } from "../../../../../../common/constants/activities/timeline";
import EventListPoint from "../EventListPoint/EventListPoint";
import EventsList from "../EventsList/EventsList";
import { cssPropertyValueSupported } from "../../../../../../common/utils/style";
import { isMobile } from "../../../../../../common/constants/user-agent";
import ReactTooltip from "react-tooltip";

@connect(
  state => {
    return {
      ...state,
      activityId: state.id,
      activityType: state.type,
      activityName: state.name,
      title: state.title
    };
  },
  buildActions
)
@InjectLocale("Activity")
class Activity extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    activityType: PropTypes.string.isRequired,
    activityName: PropTypes.string.isRequired,
    activityAlign: PropTypes.object,
    studentInstruction: PropTypes.string
  };

  state = {
    ariaText: ""
  };
  points = [];
  tooltips = [];

  touchStartHandler = () => {
    const shownTooltips = this.tooltips.filter(el => el.refs.tooltip.state.show);

    if (shownTooltips.length > 0) {
      shownTooltips.map(el => ReactTooltip.hide(el.refs.root));
    }
  };

  componentWillUnmount() {
    if (isMobile) {
      document.removeEventListener("touchstart", this.touchStartHandler);
    }
  }
  componentDidMount() {
    const { points } = this;

    if (isMobile) {
      this.tooltips = Object.keys(points)
        .map(el => points[el].getTooltipRef())
        .filter(el => el);

      document.addEventListener("touchstart", this.touchStartHandler);
    }
  }

  get listTimeline() {
    const { events } = this.props;
    const countEvents = events.length;

    return (
      <div className={styles.inner}>
        <EventsList>
          {events.map((event, i) => (
            <EventListPoint
              ref={ref => (this.points["eventListPoint" + i] = ref)}
              isFirstPoint={i === 0}
              isLastPoint={i === countEvents - 1}
              eventId={i}
              key={"eventListPoint" + i}
              date={event.startDate}
              prompt={event.prompt}
              description={event.description}
              showModal={this.showModal}
              sign={i % 2 === 0}
              dateStart={event.startDate}
              dateEnd={event.endDate}
              dateStartBC={event.isStartDateBC}
              dateEndBC={event.isEndDateBC}
            />
          ))}
        </EventsList>
      </div>
    );
  }

  get dateTimeline() {
    const { interval, intervalType, events } = this.props;

    let firstDate = events[0].startDate;
    let lastDate = events[0].startDate;
    let firstDateBC = events[0].isStartDateBC;
    let lastDateBC = events[0].isStartDateBC;

    for (let i = 0; i < events.length; i++) {
      const startDateObject = TimelineField.getProperDateObject(events[i].startDate);
      const firstDateObject = TimelineField.getProperDateObject(firstDate);
      let endDateObject = null;
      let lastDateObject = null;
      lastDateObject = TimelineField.getProperDateObject(lastDate);
      if (events[i].endDate) {
        endDateObject = TimelineField.getProperDateObject(events[i].endDate);
      }

      const BCStartLowerFirst =
        (events[i].isStartDateBC &&
          ((firstDateBC && startDateObject > firstDateObject) || !firstDateBC)) ||
        (!events[i].isStartDateBC && !firstDateBC && startDateObject < firstDateObject);

      const BCEndGreaterLast =
        (!events[i].isEndDateBC &&
          ((!lastDateBC && endDateObject > lastDateObject) || lastDateBC)) ||
        (events[i].isEndDateBC && lastDateBC && endDateObject < lastDateObject);

      const BCStartGreaterLast =
        (!events[i].isStartDateBC &&
          ((!lastDateBC && startDateObject > lastDateObject) || lastDateBC)) ||
        (events[i].isStartDateBC && lastDateBC && startDateObject < lastDateObject);

      if (BCStartLowerFirst) {
        firstDate = events[i].startDate;
        firstDateBC = events[i].isStartDateBC;
      }
      if (BCEndGreaterLast && events[i].endDate) {
        lastDate = events[i].endDate;
        lastDateBC = events[i].isEndDateBC;
      } else if (BCStartGreaterLast) {
        lastDate = events[i].startDate;
        lastDateBC = events[i].isStartDateBC;
      }
    }

    let start = TimelineField.getProperDateObject(firstDate);
    if (intervalType === "Year") {
      start.setMonth(0);
      start.setDate(1);
    } else if (intervalType === "Month") {
      start.setDate(1);
    }

    if (!lastDate) {
      lastDate = firstDate;
    }

    const endObject = TimelineField.getNextDate(
      TimelineField.getProperDateObject(lastDate),
      intervalType,
      interval,
      lastDateBC
    );
    const end = endObject.date;
    const tickCount = Math.floor(
      TimelineField.getDateDifference(start, end, intervalType, firstDateBC, endObject.BC) /
        interval
    );

    const scrollbarProps = {};
    if (
      !cssPropertyValueSupported("position", "sticky") &&
      !cssPropertyValueSupported("position", "-webkit-sticky")
    ) {
      scrollbarProps.onScroll = this.onDateTimelineScroll;
    }

    return (
      <div className={styles.timelineField} ref="timelineField" {...scrollbarProps}>
        <TimelineField
          startBC={firstDateBC}
          showModal={this.showModal}
          events={events}
          tickCount={tickCount}
          start={start}
          intervalType={intervalType}
          interval={interval}
        />
      </div>
    );
  }

  get player() {
    let content;
    const { title, eventsType } = this.props;

    switch (eventsType) {
      case Timeline.EVENTS_DATE_TYPE:
        content = this.dateTimeline;
        break;
      case Timeline.EVENTS_LIST_TYPE:
        content = this.listTimeline;
        break;
      default:
        content = <p>Wrong timeline type</p>;
    }

    return (
      <div className={styles.player}>
        <div
          style={{
            backgroundColor: title.backgroundColor
          }}
          className={styles.headerContainer}
        >
          {title.image && <img alt="" src={URLManager.getContentUrl(title.image, true)} />}
          <h2
            style={{
              textAlign: title.centered ? "center" : "left",
              color: title.textColor
            }}
          >
            {title.text}
          </h2>
        </div>
        {content}
        <div
          className={styles.footer}
          style={{
            backgroundColor: title.backgroundColor
          }}
        />
      </div>
    );
  }

  onDateTimelineScroll = e => {
    if (this.refs.timelineField && e.target) {
      const axis = this.refs.timelineField.querySelector(`.${timelineFieldStyles.axis}`);
      if (axis) axis.style.top = `${e.target.scrollTop}px`;
    }
  };

  onActivityKeyDown = e => {
    switch (e.keyCode) {
      default:
    }
  };

  showModal = (options, e) => {
    const { activityModal } = this.props;
    e.preventDefault();
    this.dialogModal.show(options);
    if (activityModal()) {
      activityModal().triggerTempHideModal();
    }
  };

  onCancelClick = () => {
    const { activityModal } = this.props;
    if (activityModal()) {
      activityModal().triggerTempHideModal();
    }
  };

  render() {
    const { studentInstruction, activityName } = this.props;
    const { ariaText } = this.state;

    return (
      <section tabIndex="0" className={styles.container} onKeyDown={this.onActivityKeyDown}>
        <AdaHelper ariaText={ariaText} />
        <ActivityHeader activityName={activityName} studentInstruction={studentInstruction} />
        <Modal onCancelClick={this.onCancelClick} ref={element => (this.dialogModal = element)} />
        {this.player}
      </section>
    );
  }
}

export default Activity;
