import styles from "./EventListPoint.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";
import classNames from "classnames";
import { Modals } from "../../../../../constants/modals";
import Tooltip from "../../../../../../common/components/Tooltip/Tooltip";
import { TOOLTIP_CONTAINER_ID } from "../../../../../../common/constants/tooltip";
import { Key } from "../../../../../../common/constants/keyboard";
import ReactTooltip from "react-tooltip";
import { Classes } from "../../../../../../common/constants/classes";

export default class EventListPoint extends PureComponent {
  static propTypes = {
    sign: PropTypes.bool.isRequired,
    description: PropTypes.string.isRequired,
    isFirstPoint: PropTypes.bool.isRequired,
    isLastPoint: PropTypes.bool.isRequired,
    prompt: PropTypes.string.isRequired,
    eventId: PropTypes.number.isRequired,
    showModal: PropTypes.func.isRequired
  };

  state = {
    tooltipShown: false
  };

  get styleLabelObject() {
    return {
      top: this.props.sign ? 80 : -140,
      paddingRight: this.props.description ? 25 : ""
    };
  }

  get styleVerticalLineObject() {
    return {
      top: this.props.sign ? 0 : -80
    };
  }

  get styleHorizontalLineObject() {
    const { isFirstPoint, isLastPoint } = this.props;

    return {
      width: isFirstPoint || isLastPoint ? "50%" : "",
      left: isFirstPoint ? "50%" : ""
    };
  }

  getTooltipRef = () => {
    return this.tooltipRef;
  };

  keyDownHandler = e => {
    if (e.which === Key.SPACEBAR) {
      const { tooltipShown } = this.state;
      const { prompt } = this.props;

      e.preventDefault();
      let currAriaText = "";
      if (tooltipShown) {
        ReactTooltip.hide(this.tooltipRef.refs.root);
      } else {
        ReactTooltip.show(this.tooltipRef.refs.root);
        currAriaText = `${prompt}`;
      }
      this.setState({
        tooltipShown: !tooltipShown,
        ariaText: currAriaText
      });
    }
  };

  blurHandler = () => {
    const { tooltipShown } = this.state;
    if (tooltipShown) {
      ReactTooltip.hide(this.tooltipRef.refs.root);
      this.setState({
        tooltipShown: false,
        ariaText: ""
      });
    }
  };

  onDescriptionClick = e => {
    this.props.showModal(
      {
        title: this.props.prompt,
        content: this.props.description,
        type: Modals.DANGER_HTML_CONTENT,
        buttonText: "OK"
      },
      e
    );
  };

  render() {
    const { description, prompt, eventId } = this.props;
    const { ariaText } = this.state;
    const buttonId = Buttons.SHOW_EVENT_DESCRIPTION;

    return (
      <div className={styles.eventlistPointWrapper}>
        <div style={this.styleHorizontalLineObject} className={styles.horizontalLine} />
        <div className={styles.point}>
          <div style={this.styleLabelObject} className={styles.eventsListLabel}>
            <Tooltip
              id={`eventListLabel${eventId}`}
              text={`${prompt}`}
              ref={element => (this.tooltipRef = element)}
              portal={document.getElementById(TOOLTIP_CONTAINER_ID)}
            >
              <div className={Classes.VISUALLY_HIDDEN} aria-live="polite" aria-atomic="true">
                {ariaText}
              </div>
              <p
                role="button"
                onKeyDown={this.keyDownHandler}
                onBlur={this.blurHandler}
                tabIndex="0"
              >
                {prompt}
              </p>
            </Tooltip>
            {description && (
              <Button
                id={buttonId}
                className={classNames(
                  buttonStyles[buttonId.split("_").join("-")],
                  styles.showDescButton
                )}
                onClick={this.onDescriptionClick}
              />
            )}
          </div>
          <div style={this.styleVerticalLineObject} className={styles.verticalLine} />
        </div>
      </div>
    );
  }
}
