export const style = (element, property, value) => {
  const propertyWithPrefix = property
    .split("-")
    .map(chunk => chunk[0].toUpperCase() + chunk.slice(1))
    .join("");
  const propertyWithoutPrefix = propertyWithPrefix[0].toLowerCase() + propertyWithPrefix.slice(1);

  if (typeof value === "undefined") {
    const style = getComputedStyle(element);

    return (
      style[`webkit${propertyWithPrefix}`] ||
      style[`moz${propertyWithPrefix}`] ||
      style[`ms${propertyWithPrefix}`] ||
      style[`o${propertyWithPrefix}`] ||
      style[propertyWithoutPrefix]
    );
  } else {
    element.style[`webkit${propertyWithPrefix}`] = value;
    element.style[`moz${propertyWithPrefix}`] = value;
    element.style[`ms${propertyWithPrefix}`] = value;
    element.style[`o${propertyWithPrefix}`] = value;
    element.style[propertyWithoutPrefix] = value;
  }
};

export const removeStyleProperty = (element, property) => {
  element.style.removeProperty(`-webkit-${property}`);
  element.style.removeProperty(`-moz-${property}`);
  element.style.removeProperty(`-ms-${property}`);
  element.style.removeProperty(`-o-${property}`);
  element.style.removeProperty(property);
};

export const prefixer = (property, value, capitalize) => {
  const propertyWithPrefix = property[0].toUpperCase() + property.slice(1);
  const propertyWithoutPrefix = property[0].toLowerCase() + property.slice(1);

  if (capitalize) {
    return {
      [`Webkit${propertyWithPrefix}`]: value,
      [`Moz${propertyWithPrefix}`]: value,
      [`Ms${propertyWithPrefix}`]: value,
      [`O${propertyWithPrefix}`]: value,
      [propertyWithoutPrefix]: value
    };
  } else {
    return {
      [`webkit${propertyWithPrefix}`]: value,
      [`moz${propertyWithPrefix}`]: value,
      [`ms${propertyWithPrefix}`]: value,
      [`o${propertyWithPrefix}`]: value,
      [propertyWithoutPrefix]: value
    };
  }
};

export const cssPropertyValueSupported = (prop, value) => {
  if (window.CSS && window.CSS.supports) {
    return window.CSS.supports(prop, value);
  }

  const d = document.createElement("div");
  d.style[prop] = value;
  return d.style[prop] === value;
};
